import React, { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import { ViewState } from '../App';

interface HeaderProps {
  onNavigate: (view: ViewState) => void;
  onContactClick: () => void;
  currentView: ViewState;
}

const Header: React.FC<HeaderProps> = ({ onNavigate, onContactClick, currentView }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Determine navbar appearance based on view and scroll state
  const isHomeTop = currentView === 'home' && !isScrolled;

  const navClasses = `fixed w-full z-50 transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] border-b ${
    isHomeTop
      ? 'bg-transparent border-white/10 py-6 text-white' 
      : 'bg-white/90 backdrop-blur-md border-gray-100 py-4 text-navy-900 shadow-sm'
  }`;

  const linkClass = `text-xs font-bold uppercase tracking-widest hover:opacity-60 transition-opacity cursor-pointer ${
    isHomeTop ? 'text-white' : 'text-navy-900'
  }`;

  const handleScrollTo = (id: string) => {
      onNavigate('home');
      setTimeout(() => {
          const el = document.getElementById(id);
          if (el) el.scrollIntoView({ behavior: 'smooth' });
      }, 100);
  };

  return (
    <header className={navClasses}>
      <div className="container mx-auto px-6 md:px-12 flex justify-between items-center h-full">

        {/* Left Menu (Desktop) */}
        <div className="hidden md:flex items-center gap-8 w-1/3">
            <button onClick={() => onNavigate('buy')} className={linkClass}>Comprar</button>
            <button onClick={() => onNavigate('sell')} className={linkClass}>Vender</button>
            <button onClick={() => handleScrollTo('estudio-ia')} className={linkClass}>Innovation Lab</button>
        </div>

        {/* Logo (Center) */}
        <div 
          className={`w-1/3 text-center cursor-pointer flex flex-col items-center justify-center hover:opacity-80 transition-opacity`}
          onClick={() => onNavigate('home')}
        >
          <span className={`text-2xl font-bold tracking-tight uppercase ${isHomeTop ? 'text-white' : 'text-navy-900'}`}>
            LAHUERTA
          </span>
          <span className={`text-[9px] tracking-[0.4em] uppercase ${isHomeTop ? 'text-white/80' : 'text-navy-900/60'}`}>
            Real Estate
          </span>
        </div>

        {/* Right Menu (Desktop) */}
        <div className="hidden md:flex items-center justify-end gap-8 w-1/3">
             <button onClick={() => handleScrollTo('nosotros')} className={linkClass}>Nosotros</button>
             <button onClick={onContactClick} className={linkClass}>Contacto</button>
        </div>

        {/* Mobile Hamburger */}
        <button 
          className={`md:hidden hover-trigger p-2 hover:opacity-70 transition-opacity ${isHomeTop ? 'text-white' : 'text-navy-900'}`}
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
           <div className="flex flex-col gap-1.5 items-end">
                <span className="w-8 h-[1px] bg-current transition-all duration-300 group-hover:w-4"></span>
                <span className="w-6 h-[1px] bg-current transition-all duration-300 group-hover:w-8"></span>
           </div>
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      <div className={`fixed inset-0 bg-navy-900 z-40 flex flex-col justify-center items-center transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isMobileMenuOpen ? 'opacity-100 visible' : 'opacity-0 invisible pointer-events-none'}`}>
          <div className="absolute top-8 right-8">
             <button onClick={() => setIsMobileMenuOpen(false)} className="hover-trigger text-white hover:opacity-70">
                <X size={32} strokeWidth={1} />
             </button>
          </div>

          <nav className="flex flex-col items-center space-y-8">
            <button onClick={() => { onNavigate('buy'); setIsMobileMenuOpen(false); }} className="text-3xl text-white font-light">Comprar</button>
            <button onClick={() => { onNavigate('sell'); setIsMobileMenuOpen(false); }} className="text-3xl text-white font-light">Vender</button>
            <button onClick={() => { handleScrollTo('estudio-ia'); setIsMobileMenuOpen(false); }} className="text-3xl text-white font-light">Innovation Lab</button>
            <button onClick={() => { handleScrollTo('nosotros'); setIsMobileMenuOpen(false); }} className="text-3xl text-white font-light">Nosotros</button>
            <button onClick={() => { onContactClick(); setIsMobileMenuOpen(false); }} className="text-3xl text-white font-light">Contacto</button>
          </nav>
      </div>
    </header>
  );
};

export default Header;

import React, { useEffect, useRef } from 'react';
import { ArrowRight } from 'lucide-react';
import gsap from 'gsap';

const Hero: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const titleLinesRef = useRef<(HTMLSpanElement | null)[]>([]);
  const textRef = useRef<HTMLParagraphElement>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const VIDEO_SRC = "/videos/fondocasanovarealestate.mp4"; 

  useEffect(() => {
    // Video Autoplay safety
    if (videoRef.current) {
      videoRef.current.defaultMuted = true;
      videoRef.current.muted = true;
      const playPromise = videoRef.current.play();
      if (playPromise !== undefined) playPromise.catch(() => {});
    }

    // GSAP Animation
    const ctx = gsap.context(() => {
      // 1. Text Reveal (Staggered Lines)
      gsap.to(titleLinesRef.current, {
        y: 0,
        opacity: 1,
        duration: 1.5,
        stagger: 0.2,
        ease: "power4.out",
        delay: 0.5 
      });

      // 2. Body Text Reveal
      gsap.fromTo(textRef.current, 
        { y: 30, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 1.2 }
      );

      // 3. Button Reveal
      gsap.fromTo(buttonRef.current,
        { scale: 0.8, opacity: 0 },
        { scale: 1, opacity: 1, duration: 0.8, ease: "back.out(1.7)", delay: 1.4 }
      );

      // 4. Parallax Effect on Video
      gsap.to(videoRef.current, {
        yPercent: 30,
        ease: "none",
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "bottom top",
          scrub: true
        }
      });
    }, containerRef);

    return () => ctx.revert();
  }, []);

  const addToRefs = (el: HTMLSpanElement | null) => {
    if (el && !titleLinesRef.current.includes(el)) {
      titleLinesRef.current.push(el);
    }
  };

  const scrollToProperties = () => {
      const el = document.getElementById('destacadas');
      if(el) el.scrollIntoView({ behavior: 'smooth' });
  }

  return (
    <section ref={containerRef} className="relative h-screen w-full overflow-hidden bg-navy-900">
      {/* Background Video with Parallax Wrapper */}
      <div className="absolute inset-0 z-0 h-[120%] -top-[10%]">
        <video 
          ref={videoRef}
          key={VIDEO_SRC}
          className="w-full h-full object-cover opacity-60"
          autoPlay loop muted playsInline preload="auto"
        >
          <source src={VIDEO_SRC} type="video/mp4" />
        </video>
        {/* Overlay Dark Blue/Black gradient */}
        <div className="absolute inset-0 bg-navy-900/40 mix-blend-multiply" />
        <div className="absolute inset-0 bg-gradient-to-t from-navy-900 via-transparent to-transparent opacity-90" />
      </div>

      {/* Content Layout */}
      <div className="relative z-10 container mx-auto px-6 md:px-12 h-full flex flex-col justify-end pb-24 md:pb-32">

        <div className="max-w-5xl">
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-serif text-white leading-[1.05] tracking-tight mb-8">
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item">Consultora Inmobiliaria</span>
            </span>
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item italic text-sand-400">Boutique</span>
            </span>
          </h1>
        </div>

        <div className="flex flex-col md:flex-row justify-between items-end border-t border-white/20 pt-8 mt-4">
            <p ref={textRef} className="text-white/80 text-lg md:text-xl font-light max-w-xl leading-relaxed mb-8 md:mb-0">
              Especialistas en la venta, gestión y transformación de activos inmobiliarios de alto valor en Madrid.
            </p>

            <button 
              ref={buttonRef}
              onClick={scrollToProperties}
              className="hover-trigger bg-white text-navy-900 px-8 py-4 rounded-md flex items-center gap-4 hover:bg-sand-400 transition-all duration-300 group hover:scale-105"
            >
              <span className="text-xs font-bold tracking-widest uppercase">Ver Propiedades</span>
              <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
            </button>
        </div>

      </div>
    </section>
  );
};

export default Hero;

