import React, { useState, useRef } from 'react';
import { Upload, Loader2, ArrowRight } from 'lucide-react';
import { generateImage, editImage, generateVideo, fileToBase64, analyzeImage } from '../services/geminiService';
import { AIState } from '../types';

const AIStudio: React.FC = () => {
  const [mode, setMode] = useState<'generate' | 'edit' | 'video' | 'analyze'>('generate');
  const [prompt, setPrompt] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [resultUrl, setResultUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<AIState>(AIState.IDLE);
  const [analysisResult, setAnalysisResult] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
      setResultUrl(null); 
      setAnalysisResult('');
    }
  };

  const handleAction = async () => {
    if (!prompt && mode !== 'analyze') return;
    if ((mode === 'edit' || mode === 'analyze') && !selectedFile) return;

    setStatus(AIState.LOADING);
    setAnalysisResult('');

    try {
      let result = '';
      if (mode === 'generate') {
        result = await generateImage(prompt, '16:9');
        setResultUrl(result);
      } else if (mode === 'edit' && selectedFile) {
        const base64Full = await fileToBase64(selectedFile);
        const base64Data = base64Full.split(',')[1];
        result = await editImage(base64Data, prompt);
        setResultUrl(result);
      } else if (mode === 'video') {
        let imageBytes = undefined;
        if (selectedFile) {
           const base64Full = await fileToBase64(selectedFile);
           imageBytes = base64Full.split(',')[1];
        }
        result = await generateVideo(prompt, '16:9', imageBytes);
        setResultUrl(result);
      } else if (mode === 'analyze' && selectedFile) {
        const base64Full = await fileToBase64(selectedFile);
        const base64Data = base64Full.split(',')[1];
        const analysis = await analyzeImage(base64Data, prompt || "Analiza esta propiedad inmobiliaria. Describe estilo, iluminación y potencial.");
        setAnalysisResult(analysis);
      }
      setStatus(AIState.SUCCESS);
    } catch (error) {
      console.error(error);
      setStatus(AIState.ERROR);
    }
  };

  return (
    <section id="estudio-ia" className="py-32 bg-navy-900 text-white">
      <div className="container mx-auto px-6 md:px-12">

        <div className="flex flex-col md:flex-row justify-between mb-16 gap-10 items-end">
            <div>
                <span className="text-xs font-bold tracking-widest text-sand-400 uppercase mb-4 block">Innovation Lab</span>
                <h2 className="text-4xl md:text-5xl font-serif text-white mb-6">
                    Diseña tu futuro con IA
                </h2>
                <p className="max-w-xl text-white/70 font-light text-lg">
                    Utiliza nuestra tecnología exclusiva (Powered by Gemini 2.5 & Veo) para visualizar el potencial de tu futura propiedad antes de comprarla. 
                </p>
            </div>
        </div>

        <div className="bg-white/5 backdrop-blur-sm rounded-2xl p-8 md:p-12 border border-white/10">

          {/* Tabs Minimalistas */}
          <div className="flex flex-wrap gap-8 md:gap-12 mb-12 border-b border-white/10 pb-1">
            {[
              { id: 'generate', label: '01. Generar Espacio' },
              { id: 'edit', label: '02. Reformar' },
              { id: 'video', label: '03. Video Tour' },
              { id: 'analyze', label: '04. Analizar' }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => {
                    setMode(tab.id as any);
                    setResultUrl(null);
                    setAnalysisResult('');
                    setPreviewUrl(null);
                    setSelectedFile(null);
                }}
                className={`text-xs uppercase tracking-widest transition-all pb-4 border-b-2 ${
                  mode === tab.id ? 'text-white border-sand-400 font-bold' : 'text-gray-500 border-transparent hover:text-white'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">

            {/* Input Section */}
            <div className="lg:col-span-4 space-y-8">

              {/* File Upload Minimal */}
              {(mode !== 'generate') && (
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="group relative h-48 rounded-lg bg-white/5 border-2 border-dashed border-white/20 flex flex-col items-center justify-center cursor-pointer hover:border-sand-400 transition-all duration-300"
                >
                  {previewUrl ? (
                    <img src={previewUrl} alt="Preview" className="w-full h-full object-cover rounded-lg opacity-80" />
                  ) : (
                    <div className="text-white/40 text-center">
                      <span className="text-[10px] uppercase tracking-widest block mb-2">Subir Imagen</span>
                      <Upload size={20} className="mx-auto opacity-50" />
                    </div>
                  )}
                  <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
                </div>
              )}

              {/* Input Styled like Prompt Field */}
              <div className="relative">
                <label className="block text-[10px] uppercase tracking-widest text-sand-400 mb-2 font-bold">Tu Visión</label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-lg p-4 text-white text-sm placeholder:text-white/30 focus:outline-none focus:bg-white/10 focus:border-sand-400 resize-none transition-all"
                  rows={4}
                  placeholder={mode === 'generate' ? "Describe la habitación de tus sueños..." : "Describe la transformación que deseas..."}
                />
              </div>

              <button
                onClick={handleAction}
                disabled={status === AIState.LOADING || (mode !== 'generate' && !selectedFile)}
                className="w-full bg-sand-400 text-navy-900 rounded-lg p-4 flex justify-between items-center hover:bg-white disabled:opacity-50 disabled:cursor-not-allowed transition-all group"
              >
                <span className="text-xs font-bold uppercase tracking-widest">
                    {status === AIState.LOADING ? 'Procesando...' : 'Generar Espacio'}
                </span>
                {status === AIState.LOADING ? <Loader2 className="animate-spin" size={16}/> : <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform"/>}
              </button>
            </div>

            {/* Output Section */}
            <div className="lg:col-span-8 bg-white/5 rounded-2xl h-[500px] border border-white/10 relative flex items-center justify-center overflow-hidden">
              {status === AIState.LOADING && (
                <div className="text-center">
                  <div className="w-16 h-1 bg-white/20 rounded-full overflow-hidden mx-auto mb-4">
                      <div className="h-full bg-sand-400 animate-[loading_1s_ease-in-out_infinite]"></div>
                  </div>
                  <p className="text-xs text-white/50 uppercase tracking-widest">Renderizando con Gemini...</p>
                </div>
              )}

              {status === AIState.SUCCESS && resultUrl && mode !== 'analyze' && (
                mode === 'video' ? (
                   <video src={resultUrl} controls autoPlay loop className="w-full h-full object-cover rounded-xl" />
                ) : (
                   <img src={resultUrl} alt="Generated" className="w-full h-full object-cover rounded-xl animate-fade-in" />
                )
              )}

              {status === AIState.SUCCESS && mode === 'analyze' && (
                <div className="p-8 w-full h-full overflow-y-auto">
                  <h4 className="font-serif font-medium text-2xl mb-6 text-white">Análisis Técnico</h4>
                  <div className="prose prose-sm prose-invert text-white/80 font-light">
                      {analysisResult}
                  </div>
                </div>
              )}

              {status === AIState.IDLE && !resultUrl && (
                <span className="text-white/20 text-xl font-light tracking-widest uppercase">Vista Previa</span>
              )}
            </div>

          </div>
        </div>
      </div>
    </section>
  );
};

export default AIStudio;

