        { scale: 0.8, opacity: 0 },
        { scale: 1, opacity: 1, duration: 0.8, ease: "back.out(1.7)", delay: 1.4 }
      );

      // 4. Parallax Effect on Video
      gsap.to(videoRef.current, {
        yPercent: 30,
        ease: "none",
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "bottom top",
          scrub: true
        }
      });
    }, containerRef);

    return () => ctx.revert();
  }, []);

  const addToRefs = (el: HTMLSpanElement | null) => {
    if (el && !titleLinesRef.current.includes(el)) {
      titleLinesRef.current.push(el);
    }
  };

  return (
    <section ref={containerRef} className="relative h-screen w-full overflow-hidden bg-navy-900">
      {/* Background Video with Parallax Wrapper */}
      <div className="absolute inset-0 z-0 h-[120%] -top-[10%]">
        <video 
          ref={videoRef}
          key={VIDEO_SRC}
          className="w-full h-full object-cover opacity-80"
          autoPlay loop muted playsInline preload="auto"
        >
          <source src={VIDEO_SRC} type="video/mp4" />
        </video>
        {/* Overlay Dark Blue/Black gradient */}
        <div className="absolute inset-0 bg-navy-900/20 mix-blend-multiply" />
        <div className="absolute inset-0 bg-gradient-to-t from-navy-900 via-transparent to-transparent opacity-80" />
      </div>

      {/* Content Layout */}
      <div className="relative z-10 container mx-auto px-6 md:px-12 h-full flex flex-col justify-end pb-24 md:pb-32">

        {/* Top Location Tag */}
        <div ref={topTextRef} className="mb-6">
            <span className="text-white/70 text-xs md:text-sm font-bold tracking-[0.3em] uppercase block">
                M A D R I D · E S P A Ñ A
            </span>
        </div>

        <div className="max-w-5xl">
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-serif text-white leading-[1.05] tracking-tight mb-8">
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item">Consultora Inmobiliaria</span>
            </span>
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item italic text-sand-400">Boutique</span>
            </span>
          </h1>
        </div>

        <div className="flex flex-col md:flex-row justify-between items-end border-t border-white/20 pt-8 mt-4">
            <p ref={textRef} className="text-white/80 text-lg md:text-xl font-light max-w-xl leading-relaxed mb-8 md:mb-0">
              Especialistas en la venta, gestión y transformación de activos inmobiliarios de alto valor.
            </p>

            <button 
              ref={buttonRef}
              onClick={() => document.getElementById('contacto')?.scrollIntoView({ behavior: 'smooth' })}
              className="hover-trigger bg-white text-navy-900 px-8 py-4 rounded-md flex items-center gap-4 hover:bg-sand-400 transition-all duration-300 group hover:scale-105"
            >
              <span className="text-xs font-bold tracking-[0.2em] uppercase">¿ H A B L A M O S ?</span>
              <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
            </button>
        </div>

      </div>
    </section>
  );
};

export default Hero;

import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';
import { ViewState } from '../App';

interface HeaderProps {
  onNavigate: (view: ViewState) => void;
  onContactClick: () => void;
  currentView: ViewState;
}

const Header: React.FC<HeaderProps> = ({ onNavigate, onContactClick, currentView }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Update styles for liquid feel
  const isDarkBg = currentView === 'home' && !isScrolled;

  const navClasses = `fixed w-full z-50 transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] border-b ${
    isScrolled 
      ? 'bg-white/80 backdrop-blur-md border-gray-100 py-4 text-navy-900 shadow-sm' 
      : 'bg-transparent border-white/10 py-6 text-white'
  }`;

  const finalTextColor = (currentView !== 'home' && !isScrolled) ? 'text-navy-900' : (isScrolled ? 'text-navy-900' : 'text-white');
  const finalNavClasses = (currentView !== 'home' && !isScrolled) ? 'fixed w-full z-50 py-6 bg-white border-b border-gray-100' : navClasses;

  const handleNavClick = (item: string) => {
    setIsMobileMenuOpen(false);
    if (item === 'Propiedades') onNavigate('buy');
    else if (item === 'Vender') onNavigate('sell');
    else if (item === 'Contacto') onContactClick();
    else if (item === 'Home') onNavigate('home');
    else {
        // Scroll to section
        onNavigate('home');
        setTimeout(() => {
             const id = item.toLowerCase().replace(' ', '-');
             const el = document.getElementById(id);
             // Note: Lenis handles native scroll events well usually
             if (el) el.scrollIntoView({ behavior: 'smooth' });
        }, 100);
    }
  };

  const menuItems = ['Home', 'Propiedades', 'Vender', 'Sobre Nosotros', 'Estudio IA', 'Contacto'];

  return (
    <header className={finalNavClasses}>
      <div className="container mx-auto px-6 md:px-12 flex justify-between items-center h-full">

        {/* Logo with Italiana Font */}
        <div 
          className={`hover-trigger text-3xl md:text-4xl font-italiana tracking-tight cursor-pointer ${finalTextColor}`}
          onClick={() => onNavigate('home')}
        >
          lahuerta
          <span className="block text-[9px] font-sans font-normal tracking-[0.4em] mt-0.5 opacity-80">REAL ESTATE</span>
        </div>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center space-x-8">
            {['Propiedades', 'Sobre Nosotros', 'Contacto'].map((item) => (
                <button 
                    key={item}
                    onClick={() => handleNavClick(item)}
                    className={`hover-trigger text-xs font-medium uppercase tracking-widest hover:opacity-70 transition-opacity ${finalTextColor}`}
                >
                    {item}
                </button>
            ))}
        </div>

        {/* Hamburger Icon */}
        <button 
          className={`hover-trigger p-2 hover:opacity-70 transition-opacity ${finalTextColor}`}
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
           <div className="flex flex-col gap-1.5 items-end">
                <span className="w-8 h-[1px] bg-current transition-all duration-300 group-hover:w-4"></span>
                <span className="w-6 h-[1px] bg-current transition-all duration-300 group-hover:w-8"></span>
           </div>
        </button>
      </div>

      {/* Full Screen Menu Overlay */}
      <div className={`fixed inset-0 bg-navy-900 z-40 flex flex-col justify-center items-center transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isMobileMenuOpen ? 'opacity-100 visible' : 'opacity-0 invisible pointer-events-none'}`}>
          <div className="absolute top-8 right-8 md:right-12">
             <button onClick={() => setIsMobileMenuOpen(false)} className="hover-trigger text-white hover:opacity-70">
                <X size={32} strokeWidth={1} />
             </button>
          </div>

          <nav className="flex flex-col items-center space-y-8">
            {menuItems.map((item, idx) => (
                <button
                key={item}
                onClick={() => handleNavClick(item)}
                className="hover-trigger text-4xl md:text-5xl text-white font-light tracking-tight hover:text-sand-400 transition-colors duration-300"
                style={{ transitionDelay: `${idx * 50}ms` }}
                >
                {item}
                </button>
            ))}
          </nav>
      </div>
    </header>
  );
};

export default Header;

import React, { useEffect, useRef } from 'react';
import gsap from 'gsap';

interface PreloaderProps {
  onComplete: () => void;
}

const Preloader: React.FC<PreloaderProps> = ({ onComplete }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const textRef = useRef<HTMLDivElement>(null);
  const subtextRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const tl = gsap.timeline({
      onComplete: onComplete
    });

    // Initial State
    gsap.set(textRef.current, { y: 50, opacity: 0 });
    gsap.set(subtextRef.current, { y: 20, opacity: 0 });

    tl.to(textRef.current, {
      y: 0,
      opacity: 1,
      duration: 1,
      ease: "power3.out",
      delay: 0.2
    })
    .to(subtextRef.current, {
      y: 0,
      opacity: 1,
      duration: 0.8,
      ease: "power3.out"
    }, "-=0.5")
    .to([textRef.current, subtextRef.current], {
      y: -50,
      opacity: 0,
      duration: 0.8,
      ease: "power2.in",
      delay: 0.5
    })
    .to(containerRef.current, {
      yPercent: -100,
      duration: 1.2,
      ease: "power4.inOut"
    }, "-=0.2");

    return () => {
      tl.kill();
    };
  }, [onComplete]);

  return (
    <div 
      ref={containerRef}
      className="fixed inset-0 z-[9999] bg-[#f9f9f9] flex flex-col items-center justify-center pointer-events-none"
    >
      <div className="overflow-hidden text-center">
        <div ref={textRef} className="text-5xl md:text-7xl font-italiana text-navy-900 tracking-tight mb-1 lowercase">
          lahuerta
        </div>
        <div ref={subtextRef} className="text-[10px] font-sans font-bold tracking-[0.5em] text-sand-400 uppercase opacity-70">
          Real Estate
        </div>
      </div>
    </div>
  );
};

export default Preloader;

